namespace {

//KeywordIndex++Autogenerated -- start of section automatically generated
enum {
	KeywordIndex_Keyword = 0,
	MaxKeywordSize = 16,
};
//KeywordIndex--Autogenerated -- end of section automatically generated

constexpr bool IsTripleString(int style) noexcept {
	return style == SCE_ERLANG_TRIPLE_STRING_SQ
		|| style == SCE_ERLANG_TRIPLE_STRING_DQ
		|| style == SCE_ERLANG_TRIPLE_SIGIL_SQ
		|| style == SCE_ERLANG_TRIPLE_SIGIL_DQ;
}

constexpr bool IsVerbatimSigil(int style) noexcept {
	return style >= SCE_ERLANG_VERBATIM_SIGIL;
}

constexpr bool IsVerbatimString(int style, bool elixir) noexcept {
	return IsVerbatimSigil(style)
		|| (!elixir && (style == SCE_ERLANG_TRIPLE_STRING_SQ || style == SCE_ERLANG_TRIPLE_STRING_DQ));
}

constexpr bool IsSigilStart(int ch, bool elixir) noexcept {
	return AnyOf(ch, '(', '[', '{', '<', '/', '|', '\'', '\"') || (!elixir && AnyOf(ch, '`', '#'));
}

constexpr int GetSigilDelimiter(int ch) noexcept {
	switch (ch) {
	case '(': return ')';
	case '[': return ']';
	case '{': return '}';
	case '<': return '>';
	default: return ch;
	}
}

constexpr bool IsOperatorSymbol(int ch) noexcept {
	// https://hexdocs.pm/elixir/operators.html
	return AnyOf(ch, '!', '%', '&', '*', '+', '-', '.', '/', '<', '=', '>', '@', '\\', '^', '|', '~');
}

// https://www.erlang.org/doc/system/data_types.html#escape-sequences
// https://hexdocs.pm/elixir/sigils.html#interpolation-and-escaping-in-string-sigils
struct EscapeSequence {
	int outerState = SCE_ERLANG_DEFAULT;
	int digitsLeft = 0;
	bool brace = false;
	bool hex = false;

	// highlight any character as escape sequence.
	bool resetEscapeState(int state, int chNext, bool elixir) noexcept {
		if (IsEOLChar(chNext) || IsVerbatimString(state, elixir)) {
			return false;
		}
		outerState = state;
		digitsLeft = 1;
		brace = false;
		hex = false;
		if (chNext == 'x' || chNext == 'u') {
			digitsLeft = (chNext == 'x') ? 3 : 5;
			hex = true;
		} else if (IsOctalDigit(chNext)) {
			digitsLeft = 3;
		}
		return true;
	}
	bool atEscapeEnd(int ch) noexcept {
		--digitsLeft;
		return digitsLeft <= 0 || !IsOctalOrHex(ch, hex);
	}
};

struct StringState {
	int state;
	int delimiter;
	int delimiterCount;
	int braceCount;
};

void ColouriseErlangDoc(Sci_PositionU startPos, Sci_Position lengthDoc, int initStyle, LexerWordList keywordLists, Accessor &styler) {
	unsigned lineState = 0;
	int indentCount = 0;
	int visibleChars = 0;
	int chBefore = 0;
	int stringDelimiter = 0;
	int delimiterCount = 0;
	EscapeSequence escSeq;
	std::vector<StringState> nestedState;

	const bool elixir = styler.GetPropertyBool("lexer.lang");
	if (startPos != 0) {
		// backtrack to restore delimiter for sigils
		BacktrackToStart(styler, PyLineStateStringInterpolation, startPos, lengthDoc, initStyle);
	}

	StyleContext sc(startPos, lengthDoc, initStyle, styler);
	if (sc.currentLine > 0) {
		lineState = styler.GetLineState(sc.currentLine - 1);
		if (initStyle > SCE_ERLANG_CHARACTER && initStyle < SCE_ERLANG_ESCAPECHAR) {
			stringDelimiter = '\"' + ((lineState >> 6) & 7);
		}
		delimiterCount = (lineState >> 9) & 0x7f;
		lineState = 0;
	}
	if (startPos == 0 && sc.Match('#', '!')) {
		// Shell Shebang at beginning of file
		lineState = PyLineStateMaskCommentLine;
		sc.SetState(SCE_ERLANG_COMMENTLINE);
		sc.Forward();
	}

	while (sc.More()) {
		switch (sc.state) {
		case SCE_ERLANG_OPERATOR:
		case SCE_ERLANG_OPERATOR2:
			sc.SetState(SCE_ERLANG_DEFAULT);
			break;

		case SCE_ERLANG_NUMBER:
			if (!IsDecimalNumberEx(sc.chPrev, sc.ch, sc.chNext) && (elixir || sc.ch != '#')) {
				sc.SetState(SCE_ERLANG_DEFAULT);
			}
			break;

		case SCE_ERLANG_STRING_SQ:
		case SCE_ERLANG_TRIPLE_STRING_SQ:
		case SCE_ERLANG_STRING_DQ:
		case SCE_ERLANG_TRIPLE_STRING_DQ:
		case SCE_ERLANG_SIGIL:
		case SCE_ERLANG_VERBATIM_SIGIL:
		case SCE_ERLANG_TRIPLE_SIGIL_SQ:
		case SCE_ERLANG_TRIPLE_SIGIL_DQ:
			if (sc.ch == '\\' && escSeq.resetEscapeState(sc.state, sc.chNext, elixir)) {
				sc.SetState(SCE_ERLANG_ESCAPECHAR);
				sc.Forward();
				if (escSeq.hex && sc.chNext == '{') {
					escSeq.brace = true;
					escSeq.digitsLeft = 9; // Unicode codepoint
					sc.Forward();
				} else if (sc.ch == '^' && IsAGraphic(sc.chNext)) {
					sc.Forward();
				}
			} else if (elixir && !IsVerbatimSigil(sc.state) && sc.Match('#', '{')) {
				nestedState.push_back({sc.state, stringDelimiter, delimiterCount, 1});
				sc.SetState(SCE_ERLANG_OPERATOR2);
				sc.Forward();
			} else if (sc.ch == stringDelimiter && (!IsTripleString(sc.state) || sc.ch == sc.chNext)) {
				if (IsTripleString(sc.state)) {
					const int count = GetMatchedDelimiterCount(styler, sc.currentPos + 1, sc.ch);
					sc.Advance(count);
					if (count < delimiterCount) {
						break;
					}
				}
				stringDelimiter = 0;
				delimiterCount = 0;
				sc.Forward();
				if (sc.state >= SCE_ERLANG_SIGIL) {
					while (IsAlpha(sc.ch)) {
						sc.Forward();
					}
				}
				sc.SetState(SCE_ERLANG_DEFAULT);
			}
			break;

		case SCE_ERLANG_ESCAPECHAR:
			if (escSeq.atEscapeEnd(sc.ch)) {
				if (escSeq.brace && sc.ch == '}') {
					sc.Forward();
				}
				sc.SetState(escSeq.outerState);
				continue;
			}
			break;

		case SCE_ERLANG_CHARACTER:
			if (sc.ch == '\\' && IsAGraphic(sc.chNext)) {
				sc.Forward();
				if (sc.ch == '^' && IsAGraphic(sc.chNext)) {
					sc.Forward();
				}
			}
			sc.ForwardSetState(SCE_ERLANG_DEFAULT);
			break;

		case SCE_ERLANG_SIGIL_ID:
		case SCE_ERLANG_IDENTIFIER:
		case SCE_ERLANG_PREPROCESSOR:
		case SCE_ERLANG_SYMBOL_ID:
			if (!IsIdentifierCharEx(sc.ch) && (elixir || sc.ch != '@')) {
				if (sc.state == SCE_ERLANG_IDENTIFIER || sc.state == SCE_ERLANG_SIGIL_ID) {
					char s[MaxKeywordSize];
					sc.GetCurrent(s, sizeof(s));
					if (sc.state == SCE_ERLANG_IDENTIFIER) {
						if (keywordLists[KeywordIndex_Keyword].InList(s)) {
							sc.ChangeState(SCE_ERLANG_KEYWORD);
							if (visibleChars == 3 && StrEqual(s, "end")) {
								lineState |= PyLineStateMaskCloseBrace;
							}
						} else if (chBefore == (elixir ? '%' : '#')) {
							sc.ChangeState(SCE_ERLANG_RECORD);
						} else if (chBefore == '?' && !elixir) {
							sc.ChangeState(SCE_ERLANG_MACRO);
						} else {
							const bool skip = elixir && (sc.ch == '?' || sc.ch == '!');
							const int chNext = sc.GetLineNextChar(skip);
							if (chNext == '(') {
								if (skip) {
									sc.Forward();
								}
								sc.ChangeState(SCE_ERLANG_FUNCTION);
							}
						}
					} else {
						if (IsSigilStart(sc.ch, elixir)) {
							stringDelimiter = GetSigilDelimiter(sc.ch);
							sc.SetState(IsUpperCase(s[1]) ? SCE_ERLANG_VERBATIM_SIGIL : SCE_ERLANG_SIGIL);
							if ((sc.ch == '\"' || sc.ch == '\'') && sc.ch == sc.chNext) {
								const int count = GetMatchedDelimiterCount(styler, sc.currentPos + 1, sc.ch);
								if (count >= 2) {
									delimiterCount = count;
									if (sc.state == SCE_ERLANG_VERBATIM_SIGIL) {
										sc.ChangeState((sc.ch == '\"') ? SCE_ERLANG_TRIPLE_SIGIL_DQ : SCE_ERLANG_TRIPLE_SIGIL_SQ);
									} else {
										sc.ChangeState((sc.ch == '\"') ? SCE_ERLANG_TRIPLE_STRING_DQ : SCE_ERLANG_TRIPLE_STRING_SQ);
									}
									sc.Advance(count);
								}
							}
						} else {
							sc.Rewind();
							sc.SetState(SCE_ERLANG_OPERATOR);
						}
						break;
					}
				}
				sc.SetState(SCE_ERLANG_DEFAULT);
			}
			break;

		case SCE_ERLANG_SYMBOL_OP:
			if (!IsOperatorSymbol(sc.ch)) {
				sc.SetState(SCE_ERLANG_DEFAULT);
			}
			break;

		case SCE_ERLANG_COMMENTLINE:
			if (sc.atLineStart) {
				sc.SetState(SCE_ERLANG_DEFAULT);
			}
			break;
		}

		if (sc.state == SCE_ERLANG_DEFAULT) {
			if (sc.ch == (elixir ? '#' : '%')) {
				sc.SetState(SCE_ERLANG_COMMENTLINE);
				if (visibleChars == 0) {
					lineState = PyLineStateMaskCommentLine;
				}
			} else if (sc.ch == '\"' || sc.ch == '\'') {
				stringDelimiter = sc.ch;
				sc.SetState((sc.ch == '\"') ? SCE_ERLANG_STRING_DQ : SCE_ERLANG_STRING_SQ);
				if (sc.ch == sc.chNext) {
					const int count = GetMatchedDelimiterCount(styler, sc.currentPos + 1, sc.ch);
					if (count >= 2) {
						static_assert(SCE_ERLANG_TRIPLE_STRING_SQ - SCE_ERLANG_STRING_SQ == SCE_ERLANG_TRIPLE_STRING_DQ - SCE_ERLANG_STRING_DQ);
						delimiterCount = count;
						sc.ChangeState(sc.state + SCE_ERLANG_TRIPLE_STRING_DQ - SCE_ERLANG_STRING_DQ);
						sc.Advance(count);
					}
				}
			} else if (sc.ch == (elixir ? '?' : '$') && IsAGraphic(sc.chNext)) {
				sc.SetState(SCE_ERLANG_CHARACTER);
			} else if (IsNumberStartEx(sc.chPrev, sc.ch, sc.chNext)) {
				sc.SetState(SCE_ERLANG_NUMBER);
			} else if (IsIdentifierStartEx(sc.ch)) {
				chBefore = sc.chPrev;
				sc.SetState(SCE_ERLANG_IDENTIFIER);
			} else if (((elixir && (sc.ch == '@' || (sc.ch == ':' && sc.chPrev != ':')))
				|| (!elixir && sc.ch == '-' && visibleChars == 0)) && IsIdentifierStartEx(sc.chNext)) {
				sc.SetState((sc.ch == ':') ? SCE_ERLANG_SYMBOL_ID : SCE_ERLANG_PREPROCESSOR);
			} else if (sc.ch == '~' && (IsAlpha(sc.chNext) || IsSigilStart(sc.chNext, elixir))) {
				sc.SetState(SCE_ERLANG_SIGIL_ID);
			} else if (sc.ch == ':' && elixir && IsOperatorSymbol(sc.chNext)) {
				sc.SetState(SCE_ERLANG_SYMBOL_OP);
			} else if (IsAGraphic(sc.ch)) {
				sc.SetState(SCE_ERLANG_OPERATOR);
				if (visibleChars == 0 && (sc.ch == '}' || sc.ch == ']' || sc.ch == ')')) {
					lineState |= PyLineStateMaskCloseBrace;
				}
				if (!nestedState.empty()) {
					sc.ChangeState(SCE_ERLANG_OPERATOR2);
					StringState &state = nestedState.back();
					if (sc.ch == '{') {
						state.braceCount += 1;
					} else if (sc.ch == '}') {
						state.braceCount -= 1;
						if (state.braceCount == 0) {
							escSeq.outerState = state.state;
							stringDelimiter = state.delimiter;
							delimiterCount = state.delimiterCount;
							nestedState.pop_back();
							sc.ForwardSetState(escSeq.outerState);
							continue;
						}
					}
				}
			}
		}

		if (visibleChars == 0) {
			if (sc.ch == ' ') {
				++indentCount;
			} else if (sc.ch == '\t') {
				indentCount = GetTabIndentCount(indentCount);
			}
		}
		if (!isspacechar(sc.ch)) {
			visibleChars++;
		}
		if (sc.atLineEnd) {
			lineState |= (indentCount << 16) | (delimiterCount << 9);
			const unsigned delimiter = stringDelimiter - '\"';
			constexpr unsigned last = '}' - '\"' + 1;
			if ((delimiter > 7 && delimiter < last) || !nestedState.empty()) {
				lineState |= PyLineStateStringInterpolation | PyLineStateMaskTripleQuote;
			} else if (delimiter <= 7) {
				lineState |= (delimiter << 6) | PyLineStateMaskTripleQuote;
			} else if (visibleChars == 0) {
				lineState |= PyLineStateMaskEmptyLine;
			}
			styler.SetLineState(sc.currentLine, lineState);
			lineState = 0;
			visibleChars = 0;
			indentCount = 0;
		}
		sc.Forward();
	}

	sc.Complete();
}

}

extern const LexerModule lmErlang(SCLEX_ERLANG, ColouriseErlangDoc, "erlang", FoldPyDoc);
